// math.js
export const PI = 3.14;
export function sum(a, b) {
  return a + b;
}
export default function main() {}

class Animal {
  constructor(name) {
    this.name = name;
  }
}
class Dog extends Animal {
  bark() {
    return `${this.name} woofs`;
  }
}

